#include <iostream>
using namespace std;
int main() {
    int n;
    cin >> n;
    int original = n;

    // Print binary
    cout << "Binary of " << original << ": ";
    bool started = false;
    for (int i = 31; i >= 0; i--) {
        if (n & (1 << i)) {
            started = true;
            cout << 1;
        } else if (started) {
            cout << 0;
        }
    }
    if (!started) cout << 0;
    cout << endl;

    // Count set bits
    int count = 0;
    int temp = original;
    while (temp) {
        temp = temp & (temp - 1);
        count++;
    }
    cout << "Number of set bits: " << count << endl;
    return 0;
}

